#include<bits/stdc++.h>
using namespace std;

const int N = 10005;
const int M = 50005;
const int L = 14;

struct E {
    int u, v, w;
    bool operator < (const E& o) const {
        return w > o.w;
    }
} e[M];

vector<pair<int, int>> g[N];
int f[N][L], mn[N][L], d[N];
int p[N];

int find(int x) {
    return p[x] == x ? x : p[x] = find(p[x]);
}

void dfs(int u, int fa, int w, int dep) {
    f[u][0] = fa;
    mn[u][0] = w;
    d[u] = dep;
    for (int i = 1; i < L; i++) {
        f[u][i] = f[f[u][i-1]][i-1];
        mn[u][i] = min(mn[u][i-1], mn[f[u][i-1]][i-1]);
    }
    for (auto& [v, wt] : g[u]) {
        if (v != fa) dfs(v, u, wt, dep + 1);
    }
}

int qry(int x, int y) {
    if (find(x) != find(y)) return -1;

    int res = 1e9;
    if (d[x] < d[y]) swap(x, y);

    int diff = d[x] - d[y];
    for (int i = 0; i < L; i++) {
        if (diff >> i & 1) {
            res = min(res, mn[x][i]);
            x = f[x][i];
        }
    }

    if (x == y) return res;

    for (int i = L-1; i >= 0; i--) {
        if (f[x][i] != f[y][i]) {
            res = min(res, mn[x][i]);
            res = min(res, mn[y][i]);
            x = f[x][i];
            y = f[y][i];
        }
    }

    res = min(res, mn[x][0]);
    res = min(res, mn[y][0]);

    return res;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);

    int n, m;
    cin >> n >> m;

    for (int i = 0; i < m; i++) {
        cin >> e[i].u >> e[i].v >> e[i].w;
    }

    sort(e, e + m);

    for (int i = 1; i <= n; i++) p[i] = i;

    for (int i = 0; i < m; i++) {
        int u = e[i].u, v = e[i].v, w = e[i].w;
        int pu = find(u), pv = find(v);
        if (pu != pv) {
            p[pu] = pv;
            g[u].push_back({v, w});
            g[v].push_back({u, w});
        }
    }

    for (int i = 1; i <= n; i++) {
        if (p[i] == i) {
            dfs(i, i, 1e9, 0);
        }
    }

    int q;
    cin >> q;
    while (q--) {
        int x, y;
        cin >> x >> y;
        cout << qry(x, y) << '\n';
    }

    return 0;
}
